import requests

# Set up RabbitMQ Management HTTP API endpoint and credentials
api_endpoint = "http://localhost:15672"
username = "guest"
password = "guest"

# Create virtual hosts for different applications
vhosts = ["app1", "app2", "app3"]
for vhost in vhosts:
    # Validate untrusted input and use secure platform APIs
    if not vhost.isalnum():
        raise ValueError("Invalid virtual host name")
    url = f"{api_endpoint}/api/vhosts/{vhost}"
    response = requests.put(url, auth=(username, password))
    if response.status_code != 201:
        print(f"Failed to create virtual host {vhost}: {response.text}")

# Set up users and grant permissions for queue operations
users = ["user1", "user2"]
for user in users:
    # Validate untrusted input and use secure platform APIs
    if not user.isalnum():
        raise ValueError("Invalid username")
    url = f"{api_endpoint}/api/users/{user}"
    response = requests.put(url, auth=(username, password))
    if response.status_code != 201:
        print(f"Failed to create user {user}: {response.text}")

    # Grant permissions for queue operations
    url = f"{api_endpoint}/api/users/{user}/permissions"
    data = {"configure": ".*", "write": ".*", "read": ".*"}
    response = requests.put(url, auth=(username, password), json=data)
    if response.status_code != 204:
        print(f"Failed to grant permissions for user {user}: {response.text}")